// File: reactapp/src/components/AppointmentForm.js
import React, { useEffect, useState } from "react";
import "./AppointmentForm.css"; // keep your styles (you already have this file)
import api from "../utils/api"; // keep using your api helper if needed

export default function AppointmentForm() {
  const [doctors, setDoctors] = useState([]);
  const [selectedDoctor, setSelectedDoctor] = useState("");
  const [patientName, setPatientName] = useState("");
  const [appointmentDate, setAppointmentDate] = useState("");
  const [appointmentTime, setAppointmentTime] = useState("");
  const [reason, setReason] = useState("");
  const [loading, setLoading] = useState(false);

  useEffect(() => {
    // load doctors list once
    const fetchDoctors = async () => {
      try {
        const res = await fetch("http://localhost:8080/api/doctors");
        if (!res.ok) return;
        const data = await res.json();
        setDoctors(data);
        if (data.length > 0) setSelectedDoctor(String(data[0].id));
      } catch (err) {
        console.error("Failed to load doctors", err);
      }
    };
    fetchDoctors();
  }, []);

  const handleSubmit = async (e) => {
    e.preventDefault();
    if (!patientName || !selectedDoctor || !appointmentDate || !appointmentTime) {
      alert("Fill patient name, doctor, date and time.");
      return;
    }

    setLoading(true);
    try {
      // 1) create patient
      const createPatientResp = await fetch("http://localhost:8080/api/patients", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ name: patientName.trim() }),
      });

      if (!createPatientResp.ok) {
        const txt = await createPatientResp.text();
        console.error("createPatient failed:", txt);
        alert("Failed to create patient: " + txt);
        setLoading(false);
        return;
      }

      const patientData = await createPatientResp.json();
      const patientId = patientData.id;
      if (!patientId) {
        alert("Server returned invalid patient id.");
        setLoading(false);
        return;
      }

      // 2) create appointment using returned patientId
      const appointmentPayload = {
        patientId: String(patientId),
        doctorId: String(selectedDoctor),
        appointmentDate, // expects yyyy-MM-dd from <input type="date">
        appointmentTime, // expects HH:mm from <input type="time">
        reason,
      };

      const createApptResp = await fetch("http://localhost:8080/api/appointments", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify(appointmentPayload),
      });

      if (!createApptResp.ok) {
        const errText = await createApptResp.text();
        console.error("createAppointment failed:", errText);
        alert("Failed to book appointment: " + errText);
        setLoading(false);
        return;
      }

      const appt = await createApptResp.json();
      alert("Appointment booked (id: " + appt.id + ")");
      // reset form lightly
      setPatientName("");
      setAppointmentDate("");
      setAppointmentTime("");
      setReason("");
    } catch (err) {
      console.error(err);
      alert("Server error while booking.");
    } finally {
      setLoading(false);
    }
  };

  return (
    <form className="appointment-form" onSubmit={handleSubmit}>
      <h2>Book Appointment</h2>

      <div className="form-group">
        <label>Patient Name</label>
        <input
          type="text"
          value={patientName}
          onChange={(e) => setPatientName(e.target.value)}
          required
          placeholder="Enter patient name"
        />
      </div>

      <div className="form-group">
        <label>Doctor</label>
        <select
          value={selectedDoctor}
          onChange={(e) => setSelectedDoctor(e.target.value)}
          required
        >
          {doctors.map((d) => (
            <option key={d.id} value={String(d.id)}>
              {d.name} {d.specialization ? `(${d.specialization})` : ""}
            </option>
          ))}
        </select>
      </div>

      <div className="form-group">
        <label>Date</label>
        <input
          type="date"
          value={appointmentDate}
          onChange={(e) => setAppointmentDate(e.target.value)}
          required
        />
      </div>

      <div className="form-group">
        <label>Time</label>
        <input
          type="time"
          value={appointmentTime}
          onChange={(e) => setAppointmentTime(e.target.value)}
          required
        />
      </div>

      <div className="form-group">
        <label>Reason</label>
        <textarea
          value={reason}
          onChange={(e) => setReason(e.target.value)}
          placeholder="Reason for appointment"
        />
      </div>

      <div className="form-actions">
        <button type="submit" disabled={loading}>
          {loading ? "Booking..." : "Book Appointment"}
        </button>
      </div>
    </form>
  );
}
